head.script:
scwin.g_sLoginDept = "";
scwin.empNo_Yn = "";
scwin.vEmpNo = "";
scwin.empNo = "";
scwin.houseNo = "";
scwin.privAdmin = "";
scwin.txtCoClsCd = "";
scwin.RETRIEVE_AUTH = "R";

scwin.onpageload = function() {
    scwin.g_sLoginDept = $c.ses.getAcctDeptCd();
    scwin.vEmpNo = $c.ses.getEmpNo();
    scwin.empNo = $c.ses.getUserId();
    scwin.privAdmin = $c.ses.getPrivAdmin();

    scwin.params = $c.data.getParameter();
    if (scwin.params != null && scwin.params["houseNo"] != null) {
        scwin.houseNo = scwin.params["houseNo"];
    } else {
        scwin.houseNo = "";
    }

    scwin.f_OnLoad();
};

scwin.f_OnLoad = async function() {
    scwin.f_empNo();

    if (!$c.gus.cfIsNull(scwin.params) && scwin.params["houseNo"] != null && scwin.params["houseNo"] != "") {
        ed_hhblno.setValue(scwin.params["houseNo"]);
    }

    if (scwin.houseNo != "") {
        ed_hhblno.setValue(scwin.houseNo);
    }
};

scwin.f_empNo = async function() {
    let grp_cd = "FI624";
    let pCode = scwin.empNo;

    let param1 = " CD      as COL1 "
        + ",CD_NM 	as COL2 "
        + ",'' 		as COL3 "
        + ",'' 		as COL4 "
        + ",'' 		as COL5 "
        + ",'' 		as COL6 "
        + ",''      as COL7 "
        + ",''      as COL8 "
        + ",''      as COL9 "
        + ",''      as COL10";

    let param2 = " TB_ZZ002 ";

    let param3 = " AND GRP_CD = '" + grp_cd + "'"
        + " AND USE_YN = '1' "
        + " AND CD_NM = '" + pCode + "' ";

    let param4 = "CD";

    // TODO: ds_empNo 동적 쿼리 조회 — 원본은 DataId + Reset() 방식, WebSquare에서는 submission 파라미터 방식으로 전환 필요
    await $c.sbm.execute(sbm_empNo);
};

scwin.f_setCompanyInfo = function() {
};

scwin.f_PopUpCompanyInfo = function(pWinCloseTF) {
};

scwin.f_changeCheck = function() {
};

scwin.f_Retrieve = async function() {
    if (ed_hhblno.getValue() == "") {
        await $c.win.alert("House No는 반드시 입력이 되어야 합니다.");
        ed_hhblno.setFocus();
        return;
    }
    scwin.f_setFileUpDownFrame(ed_hhblno.getValue());
};

scwin.f_Retrieve1 = async function() {
    await $c.sbm.execute(sbm_search1);
};

scwin.f_Retrieve2 = async function() {
    await $c.sbm.execute(sbm_search2);
};

scwin.f_userToExcel1 = async function(gr_evid1, gridName) {
    let objGrd = $p.getComponentById(gr_evid1);
    let objDs = $p.getComponentById(objGrd.getDataListId());

    if (objDs.getRowCount() <= 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_009, Array("데이타"));
        return false;
    }

    $c.data.downloadGridViewExcel(gr_evid1, {"fileName": gridName + ".xlsx", "sheetName": gridName});
};

scwin.getSlipNoRegistID = async function(slipNo) {
    let param1 = " A.SLIP_NO   as COL1 "
        + ",A.REG_ID    as COL2 "
        + ",A.SLIP_DT   as COL3 "
        + ",B.USER_NM   as COL4 "
        + ",A.DRAW_ACCT_DEPT_CD  as COL5 "
        + ",'' 			as COL6 "
        + ",'' 			as COL7 "
        + ",'' 			as COL8 "
        + ",'' 			as COL9 "
        + ",'' 			as COL10 ";

    let param2 = " TB_FI101 A, TB_ZZ315 B";

    let param3 = " AND A.REG_ID = B.USER_ID "
        + " AND A.SLIP_NO = '" + slipNo + "'";

    let param4 = " A.SLIP_NO ";

    // TODO: ds_checkRegistID 동적 쿼리 조회 — 원본은 DataId + Reset() 방식, WebSquare에서는 submission 파라미터 방식으로 전환 필요
    await $c.sbm.execute(sbm_checkRegistID);
};

scwin.getFixedAsetCount = async function(slipNo) {
    let param1 = " SUM( CASE WHEN FROM_CLS_CD = '20' "
        + "			  THEN 1 "
        + "  		  ELSE 0 "
        + "		 END ) AS COL1 "
        + ",''    		as COL2 "
        + ",''   		as COL3 "
        + ",''   		as COL4 "
        + ",''  		as COL5 "
        + ",'' 			as COL6 "
        + ",'' 			as COL7 "
        + ",'' 			as COL8 "
        + ",'' 			as COL9 "
        + ",'' 			as COL10 ";

    let param2 = " TB_ZZ527 ";

    let param3 = " AND SLIP_NO = '" + slipNo + "'";

    let param4 = " COL1 ";

    // TODO: ds_fixedAsetCount 동적 쿼리 조회 — 원본은 DataId + Reset() 방식, WebSquare에서는 submission 파라미터 방식으로 전환 필요
    await $c.sbm.execute(sbm_fixedAsetCount);
};

scwin.getAcctDeptCd = async function(slipDt, drawAcctDeptCd) {
    let param1 = " ACCT_DEPT_CD   as COL1 "
        + ",ACCT_DEPT_CD   as COL2 "
        + ",''   		as COL3 "
        + ",''   		as COL4 "
        + ",''  		as COL5 "
        + ",'' 			as COL6 "
        + ",'' 			as COL7 "
        + ",'' 			as COL8 "
        + ",'' 			as COL9 "
        + ",'' 			as COL10 ";

    let param2 = "(SELECT * FROM TB_CO011 WHERE ACCT_YEAR = SUBSTR('" + slipDt + "',1,4))"
        + "  START  WITH ACCT_DEPT_CD = ( "
        + "                                 SELECT UPPER_ACCT_DEPT_CD "
        + "                                   FROM TB_CO011 "
        + "                                  WHERE ACCT_YEAR = SUBSTR('" + slipDt + "',1,4)"
        + "                                    AND ACCT_DEPT_CD = '" + drawAcctDeptCd + "'"
        + "							 ) "
        + "  CONNECT BY PRIOR ACCT_DEPT_CD = UPPER_ACCT_DEPT_CD ";

    // TODO: ds_bizdiv 동적 쿼리 조회 — 원본은 DataId + Reset() 방식, WebSquare에서는 submission 파라미터 방식으로 전환 필요
    await $c.sbm.execute(sbm_bizdiv);
};

scwin.f_userToExcel2 = async function(gr_evid2, gridName) {
    let objGrd = $p.getComponentById(gr_evid2);
    let objDs = $p.getComponentById(objGrd.getDataListId());

    if (objDs.getRowCount() <= 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_009, Array("데이타"));
        return false;
    }
    $c.data.downloadGridViewExcel(gr_evid2, {"fileName": gridName + ".xlsx", "sheetName": gridName});
};

scwin.f_print_certi = function() {
    // TODO: OZ Report 연동 — 원본은 cfOZReport 기반 리포트 출력, WebSquare 리포트 연동으로 전환 필요
};

scwin.f_forwardingPrint = function(selPchClsCd) {
    let rowPosition = ds_evid1.getRowPosition();

    if (selPchClsCd == "INVOICE") {
        if (ds_evid1.getCellData(rowPosition, "odrNo").substr(1, 1) == "A") {
            // TODO: OZ Report 연동 — ac_101_01_01_air.ozr
            let odiParam = {};
            odiParam["KCOMCD"] = "DBEX";
            odiParam["PRTN_GRP_NO"] = ds_evid1.getCellData(rowPosition, "prtnGrpNo");
            odiParam["SEAAIR"] = "A";
            if (ds_evid1.getCellData(rowPosition, "odrNo").substr(2, 1) == "I") {
                odiParam["IOGB"] = "I";
            } else {
                odiParam["IOGB"] = "O";
            }
            odiParam["BILG_CLNT_NO"] = ds_evid1.getCellData(rowPosition, "bilgClntNo");
            odiParam["USER_ID"] = scwin.empNo;
            odiParam["TYPE"] = "5";
            odiParam["RMK"] = "Y";
            odiParam["ENG"] = "1";
            odiParam["PIC"] = "2";
            // TODO: cfOZReport 호출 전환
        } else {
            // TODO: OZ Report 연동 — ac_101_01_01_sea.ozr
            let odiParam = {};
            odiParam["KCOMCD"] = "DBEX";
            odiParam["PRTN_GRP_NO"] = ds_evid1.getCellData(rowPosition, "prtnGrpNo");
            odiParam["SEAAIR"] = "S";
            if (ds_evid1.getCellData(rowPosition, "odrNo").substr(2, 1) == "I") {
                odiParam["IOGB"] = "I";
            } else {
                odiParam["IOGB"] = "O";
            }
            odiParam["BILG_CLNT_NO"] = ds_evid1.getCellData(rowPosition, "bilgClntNo");
            odiParam["USER_ID"] = scwin.empNo;
            odiParam["TYPE"] = "5";
            odiParam["RMK"] = "Y";
            odiParam["ENG"] = "1";
            odiParam["PIC"] = "2";
            // TODO: cfOZReport 호출 전환
        }
    } else if (selPchClsCd == "PARTNER") {
        let emp_no = scwin.vEmpNo;

        let odiParam = {};
        odiParam["KCOMCD"] = "DBEX";
        odiParam["PRTN_GRP_NO"] = ds_evid1.getCellData(rowPosition, "prtnGrpNo");
        if (ds_evid1.getCellData(rowPosition, "odrNo").substr(1, 1) == "A") {
            odiParam["SEAAIR"] = "A";
        } else {
            odiParam["SEAAIR"] = "S";
        }
        if (ds_evid1.getCellData(rowPosition, "odrNo").substr(2, 1) == "I") {
            odiParam["IOGB"] = "I";
        } else {
            odiParam["IOGB"] = "O";
        }
        odiParam["BILG_CLNT_NO"] = ds_evid1.getCellData(rowPosition, "bilgClntNo");
        odiParam["USER_ID"] = scwin.empNo;
        odiParam["TYPE"] = "0";
        odiParam["EMP_NO"] = emp_no;
        odiParam["PIC"] = "2";
        // TODO: cfOZReport 호출 전환
    }
};

