scwin.f_eSeroConnect = async function() {
    let valueObject = {};
    // TODO: ed_slipNo 컴포넌트가 body에 없으므로 원본 로직 참조 필요
    // valueObject.slipNo = ed_slipNo.getValue();

    let rtnValue = await $c.win.openPopup("/ui/ac/fi/taxbiz/evidmgnt/fi_403_01_01b.xml", {
        width: 1030,
        height: 680,
        modal: true,
        data: valueObject
    });

    if (rtnValue == "Y") {
        scwin.f_Retrieve();
    }
};

scwin.f_setFileUpDownFrame = function(houseNo) {
    let url = "/ui/il/common/xml/ilCommonFilePopup_02.xml"
        + "?houseNo=" + houseNo;
    fileUpDownFrame.setSrc(url);
};

scwin.f_winClose = function() {
    $c.win.closePopup("Y");
};

scwin.onCloseWindow = function() {
    $c.win.closePopup("Y");
};

scwin.f_OpenCommonPopUp = function(gubun, pCode, pName, pClose, pAllSearch, row) {
    let rtnList = new Array();
    let pSelectID = "";
    let pWtitleSearch = null;
    // TODO: ed_coCd 컴포넌트가 body에 없으므로 원본 로직 참조 필요
    let param = ",,,0";

    if (gubun == 4) {
        pSelectID = "retrieveAcctDeptCdInfo6";
        pWtitleSearch = null;
    }

    rtnList = $c.gus.cfCommonPopUp(pSelectID, pCode, pName, pClose, null, null, null, null, param, null, null, null, null, null, pAllSearch, pWtitleSearch);

    if (gubun == 4) {
        // TODO: ed_deptCd, txt_deptNm 컴포넌트가 body에 없으므로 원본 로직 참조 필요
        // $c.gus.cfSetReturnValue(rtnList, ed_deptCd, txt_deptNm);
    }
};

scwin.f_ChkOpenCommonPopUp = function(gubun, inObj, pairObj, isCode) {
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) return;

    $c.gus.cfClearPairObj(pairObj);

    let pVal = $c.gus.cfGetValue(inObj);

    if (isCode == null || isCode == true) {
        scwin.f_OpenCommonPopUp(gubun, pVal, "", "T", "T");
    } else {
        scwin.f_OpenCommonPopUp(gubun, "", pVal, "T", "T");
    }
};

scwin.f_SearchPopUp = function(flag, check, isCdYn) {
    let rtnList = new Array();
    switch (flag) {
        case "2":
            // TODO: ed_regId, txt_empNm, coCd 컴포넌트가 body에 없으므로 원본 로직 참조 필요
            let param = "" + scwin.txtCoClsCd;

            // rtnList = $c.gus.cfCommonPopUp("retrieveAcEmpInfo", ed_regId.getValue().trim(), txt_empNm.getValue(), check, null, null, null, null, param, null, null, null, null);
            // scwin.f_resultPopEd(ed_regId, txt_empNm, rtnList);
            break;
    }
};

scwin.f_resultPopEd = function(strCd, strNm, rtnList) {
    if (rtnList != null) {
        if (rtnList[0] == "N/A") {
            return;
        }
        strCd.setValue(rtnList[0]);
        strNm.setValue(rtnList[1]);
    } else {
        strCd.setValue("");
        strNm.setValue("");
    }
};

scwin.f_userToExcel = async function(gr_evid, gridName) {
    let objGrd = $p.getComponentById(gr_evid);
    let objDs = $p.getComponentById(objGrd.getDataListId());

    if (objDs.getRowCount() <= 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_009, Array("데이타"));
        return false;
    }
    $c.data.downloadGridViewExcel(gr_evid, {"fileName": gridName + ".xlsx", "sheetName": gridName});
};

scwin.f_checkPopEd2 = function(strCd, strNm, flag) {
    strNm.setValue("");

    if (strCd.getValue().trim() != "") {
        scwin.f_SearchPopUp(flag, "T");
    }
};

